VALUES
  ('social-worker-moex-02761', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者在各方的多重目標、多重限制條件下，運用各方資源與資訊，為需要合作的各方解決問題，必提 出各方可接受的方案，使各方依此方案採取行動，並獲致多贏的結果。這段敘述的重點是說明那一項管 理工作？', '["溝通", "協調", "共識", "整合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02762', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '這些年來，臺灣一些社會服務機構引進平衡計分卡（balance scorecard, BSC），作為組織績效管理的策 略。下列有關各機構運用平衡計分卡的敘述何者錯誤？', '["社會服務之績效關鍵指標（key performance indicators, KPI）的設立不易，核心指標很難確定", "運用平衡計分卡並不需要大量的數據支撐，很適合小型的非營利機構的操作", "社會服務的成本很難精確估算", "社會服務成本不像企業成本，不易對應到社會服務的效益分析"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02763', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '麥卡錫（Jerome McCarthy, 1960）曾在其所出版之《基礎市場行銷：管理方法》一書中，率先提出行銷組 合的4P因素，下列那一個名詞是屬於麥卡錫所提之行銷組合的4P因素之一：', '["promotion（推廣）", "producing（生產）", "purchasing（消費）", "probing（調查）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02764', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在工作團隊裡幫助他人，自願去做較多工作執行超過基本角色要求，這在組織研究中稱為：', '["聯繫者", "組織公民行為", "組織管理行為", "組織正向行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02765', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新公共管理的概念已經在全球累積一定的效應，對政府組織及社會服務機構都產生了一連串的影響，下 列那一項敘述錯誤？', '["政府將服務訂契約委外提供，自己成為服務的購買者，然服務的控制權仍在其手上", "社會服務提供者之間的競爭，會帶來更節省、更有效率及更有效果的服務", "政府組織及社會服務機構的管理者必須更注意服務使用者的意見回饋，並儘可能讓使用者了解他們所 使用的服務", "新公共管理賦予專業人員更多權力，並且堅持專業人員應有一定的「管理權」，如此組織才能提供更 有品質的專業服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02766', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一個組織做決策的方式依人數多寡可分為個人決策與團體決策。下列那一項敘述是個人決策的缺點？', '["責任模糊", "少數壟斷", "正當性低", "費時又缺乏效率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02767', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關國民年金法相關規定的敘述，下列何者錯誤？', '["國民年金之保險事故有老年、生育、身心障礙以及死亡", "老年基本保證年金的費用來自保險費", "生育給付的標準為分娩或早產者發給1個月的生育給付", "低收入戶的保費在直轄市由直轄市政府全額負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02768', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'Esping-Anderson（1990）採用「去商品化」的概念來測量下列那一個福利國家價值的實踐程度？', '["全球化程度", "階層化程度", "政府的自由裁量權", "社會福利作為一種公民權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02769', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會政策制定模式，下列敘述何者正確？', '["理性模式會全盤考量局勢，並衡量社會政策所能達到的社會、政治及經濟價值", "有限理性模式是指在有限的時間、知識與成本考量下，以現有政策為基礎，進行小幅度政策調整，以 減少爭議", "漸進途徑認為政策無法避免團體間的利益衝突，一旦牽扯資源的分配，便很難讓所有群體都滿意政策 的決定", "政治途徑主張不同意識形態所堅持的理性存有差異，所以應在可接受成本支出下，尋找最佳方案，以 實現重要價值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02770', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於女性主義觀點對福利國家的分析，下列敘述何者錯誤？', '["主張唯有強調對女性地位有正確理解的福利國家分析，才能揭示現代福利主義的完整意義", "主張社會政策與經濟政策一樣重要", "對福利國家的矛盾態度：一方面認可福利國家改善女性生活和機會，另方面批判福利服務提供背後隱 含的家庭責任價值", "激進派女性主義認為福利國家延伸了女性經濟、社會權的可能性及空間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02771', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依少年事件處理法規定，下列敘述何者錯誤？', '["少年行蹤不明者，少年法院不得公告或登在報紙公開之", "經常逃學逃家者，有觸犯刑罰法律之虞者，由少年法院依本法處理", "少年法院調查結果認為情節輕微，得為不付審理之裁定，並轉介兒童及少年福利機構為適當輔導", "少年觀護所收容少年期間，調查或審理不得超過6個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02772', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依老人福利法規定，爲保護老人財產安全，直轄市、縣（市）主管機關應鼓勵老人如何處理其財產？', '["交給信託業者代為管理", "交給社會工作者管理", "交由慈善機構保管", "交由親朋好友保管"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02773', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會政策所崇尚的價值，下列敘述何者正確？', '["Bradshaw（1972）主張以四個方法定義需要（need）：感覺的需要、表達的需要、觀察的需要、比較 的需要", "Marshall（1950）將社會權界定為人們在社會中所應具有免於受到歧視的基本自由", "權利的合法化可以透過以需要為基礎（need-based）、應得為基礎（deserve-based）兩種方式而認定", "Nozick主張正義的核心在於勞動，Rawls主張正義的核心在於能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
